sys_script.script:
/**
 * Business Rule: After consumption record is inserted
 * - Decrements venue inventory quantity
 * - Fires events for low/out-of-stock
 * - Creates activity feed entry
 */
(function consumptionAfterInsert(current, previous) {
    var venueInv = new GlideRecord('x_1838075_pub_cr_0_venue_inv');
    venueInv.addQuery('venue', current.getValue('venue'));
    venueInv.addQuery('beer_model', current.getValue('beer_model'));
    venueInv.query();

    if (venueInv.next()) {
        var qty = parseInt(venueInv.getValue('quantity_on_hand'), 10) - 1;
        venueInv.setValue('quantity_on_hand', qty);
        venueInv.update();

        if (qty <= 0) {
            gs.eventQueue('x_1838075_pub_cr_0.inventory.out_of_stock', venueInv, venueInv.getValue('venue'), venueInv.getValue('beer_model'));
        } else if (qty <= 5) {
            gs.eventQueue('x_1838075_pub_cr_0.inventory.low_stock', venueInv, venueInv.getValue('venue'), venueInv.getValue('beer_model'));
        }
    }

    // Create activity feed entry
    var activity = new GlideRecord('x_1838075_pub_cr_0_activity_feed');
    activity.initialize();
    activity.setValue('user', current.getValue('user'));
    activity.setValue('activity_type', 'scan');
    activity.setValue('beer_model', current.getValue('beer_model'));
    activity.setValue('venue', current.getValue('venue'));
    activity.setValue('event', current.getValue('event'));
    activity.setValue('message', 'Consumed a beer');
    activity.insert();
})(current, previous);
